class StudentProfile {
private:
    std::string fullName;
    int studentID;
    double gpa;

public:
    StudentProfile(const std::string& name, int id, double gpa) 
        : fullName(name), studentID(id), gpa(gpa) {}

    std::string getFullName() const {
        return fullName;
    }

    int getStudentID() const {
        return studentID;
    }

    double getGPA() const {
        return gpa;
    }

    void setFullName(const std::string& name) {
        fullName = name;
    }

    void setStudentID(int id) {
        studentID = id;
    }

    void setGPA(double gpa) {
        gpa = gpa;
    }
};
```

